static inline uint8_t buddy_pack_palette_index(const uint8_t* frame, uint16_t pixel_index) {
  const uint32_t bit_index = pixel_index * 5U;
  const uint16_t byte_index = bit_index / 8U;
  const uint8_t bit_offset = bit_index % 8U;
  uint32_t window = 0;
  window |= (uint32_t)pgm_read_byte(frame + byte_index);
  window |= ((uint32_t)pgm_read_byte(frame + byte_index + 1U)) << 8U;
  window |= ((uint32_t)pgm_read_byte(frame + byte_index + 2U)) << 16U;
  return (window >> bit_offset) & 0x1FU;
}

